USE velox_courier;
GO

-- Obtener el último código para continuar la secuencia
DECLARE @siguiente INT;
SELECT @siguiente = ISNULL(MAX(CAST(SUBSTRING(codigo,3,LEN(codigo)) AS INT)),1000) + 1
FROM ordenes WHERE codigo LIKE 'C-%';

INSERT INTO ordenes (
    codigo, fecha, id_tienda, id_origen, id_distrito, id_motorizado,
    dest_nombre, estado, metodo_pago,
    delivery_base, monto_adicional, monto_cobrado, monto_producto,
    pago_moto_base, pago_moto_adicional,
    producto_especial, observaciones
) VALUES (
    'C-' + CAST(@siguiente + 0 AS NVARCHAR(20)),
    '2026-07-01',
    (SELECT TOP 1 id FROM tiendas WHERE nombre = 'AELE'),
    (SELECT TOP 1 id FROM origenes WHERE nombre = 'GAMARRA'),
    (SELECT TOP 1 id FROM distritos WHERE nombre = 'SAN MIGUEL'),
    (SELECT TOP 1 id FROM motorizados WHERE nombre = 'JEANPIER'),
    N'MOISES',
    'entregado',
    'yape',
    10.0, 0, 10.0, 0,
    0, 0,
    0, N''
);
